import{_ as e,p as t,q as r,a1 as i}from"./framework-e0dd9823.js";const h={},l=i('<h1 id="特殊疑问句" tabindex="-1"><a class="header-anchor" href="#特殊疑问句" aria-hidden="true">#</a> 特殊疑问句</h1><p>特殊疑问句是英语中以特殊疑问词开头，对句中某一成分提问的句子（以特殊疑问词（组）开头的以寻求信息为目的的疑问句）。</p><p>常用的疑问词有</p><table><thead><tr><th>疑问词</th><th>意思</th></tr></thead><tbody><tr><td>where</td><td>在哪里</td></tr><tr><td>what</td><td>什么</td></tr><tr><td>why</td><td>为什么</td></tr><tr><td>whose</td><td>谁的</td></tr><tr><td>when</td><td>什么时候</td></tr><tr><td>whom</td><td>谁</td></tr><tr><td>who</td><td>谁</td></tr><tr><td>which</td><td>哪一个</td></tr><tr><td>how</td><td>如何，怎样</td></tr></tbody></table><h2 id="where-在哪里-哪里" tabindex="-1"><a class="header-anchor" href="#where-在哪里-哪里" aria-hidden="true">#</a> where 在哪里，哪里</h2><ol><li>做地点状语</li></ol><p>where 做地点状语一般只能出现的主谓宾的句子，主系表不可以。</p><p>做地点状语，句型：“Where + 主语 + 谓语 + 宾语”。疑问词后面必须使用一般疑问句，所以 where 后面的主谓宾必须是一般疑问句的结构。</p><p>例句：</p><ul><li>Where do you learn English?（一般现在时态）</li><li>Where do they work?</li><li>Where do your friends sell clothes?</li><li>Where does Nick teach English?（单三）</li><li>Where does she bake sweet potatoes every day?</li><li>Where does he run every morning?</li><li>Where will she buy a house next year?（一般将来时态）</li><li>Where will you business next month?</li><li>Where will your aunt dance tonight?</li><li>Where is she going to look for a job next month?(be going to)</li><li>Where am I going to teach English in the future?</li><li>Where are my friends going to swim tomorrow?</li><li>Where is she drinking wine now?（现在进行时态）</li><li>Where are they running now?</li><li>Where is Nick baking sweet potatoes?</li><li>Where has she gone to?（现在完成时态）</li><li>Where has she bought a house?</li><li>Where have they learned English for year?</li></ul><ol start="2"><li>作表语</li></ol><p>句型：“Where + be + 主语 + 状语？”，因为 where 本身是疑问词，所以必须放开头，然后，有因为疑问词后面必须是一般疑问句结构，所以 be 动词要移到主语前面，因此，where 作表语的句型，就变成了：“表语 + 系动词 + 主语 + 状语？”，这就是典型的状语。</p>',12),o=[l];function d(a,n){return t(),r("div",null,o)}const c=e(h,[["render",d],["__file","special-question.html.vue"]]);export{c as default};
